fn compute_adl_requirement(
    _ex: &Exchange,
    _pos: &PositionState,
    _asset_idx: u64,
    _user: &UserAddress,
) {
}

pub fn build_adl_candidate_set(exchange: &Exchange) -> BTreeSet<UserAddress> {
    let mut filter_users_opt: Option<Box<BTreeSet<UserAddress>>> = None;
    let iter_vec: Vec<AdlIterEntry> =
        adl_init_user_position_iterators(&exchange.adl_state, 2, &mut filter_users_opt);
    let mut result: BTreeSet<UserAddress> = BTreeSet::new();
    let exchange_saved: &Exchange = exchange;
    let user_state_ptr_1: &UserState = &exchange.default_user;

    let entry_count: usize = iter_vec.len();
    let mut i: usize = 0;
    while i < entry_count {
        let entry_cursor: &AdlIterEntry = &iter_vec[i];
        let discriminant: u64 = entry_cursor.discriminant;
        let asset_idx: u64 = entry_cursor.asset_idx;
        let user_address: UserAddress = entry_cursor.user_address.clone();
        let direction_byte: u32 = entry_cursor.direction_byte;

        let user_state_ptr: &UserState = exchange
            .users
            .get(&user_address)
            .unwrap_or(user_state_ptr_1);

        let user_addr_copy: UserAddress = user_address.clone();
        let positions_clone: BTreeMap<u64, PositionState> = user_state_ptr.positions.clone();
        let orders_root: BTreeMap<u64, OrderState> = user_state_ptr.orders.clone();
        let positions_root: BTreeMap<u64, PositionState> = positions_clone;

        result.insert(user_addr_copy);

        if discriminant & 1 != 0 {
            if let Some(rhs) = positions_root.get(&asset_idx) {
                compute_adl_requirement(exchange_saved, rhs, asset_idx, &user_address);
            }
        } else if let Some(lhs_2) = positions_root.get(&asset_idx) {
            compute_adl_requirement(exchange_saved, lhs_2, asset_idx, &user_address);
        }

        let _ = direction_byte;
        let _ = orders_root;
        i += 1;
    }
    result
}

