}
pub struct OraclePxRef { pub asset: u64, pub px_unit: u64, pub px_value: u64 }
pub struct UserMarginShortfall {
    pub total_equity: Option<UnitQty>,
    pub margin_req: Option<UnitQty>,
    pub abs_ntl: Option<UnitQty>,
    pub iso_equity: Option<UnitQty>,
}

#[allow(unused_variables, unused_assignments)]
pub fn compute_user_margin_and_shortfall(ch: &UserState, user_state: &OraclePxRef) -> UserMarginShortfall {
    // Read px-table base+len (HLIL names rcx, rcx_1)
    let rcx = user_state.px_unit;
    let rcx_1 = user_state.px_value;
    let oracle = rcx;
    let mkt_data_field_0x40 = rcx;

    // Read account_equity scalars from this/UserState
    let r8 = ch.account_equity.as_ref().map_or(0u64, |q| q.value);
    let rbx = ch.account_equity.as_ref().map_or(0u64, |q| q.unit ^ q.value);
    let total_equity_unit_3 = ch.account_equity.as_ref().map_or(0u64, |q| q.unit);
    let acct_equity_value = r8;

    // Per-output accumulators (initialized: total_equity := account_equity; others := None)
    let total_equity_tag = rbx;
    let total_equity_unit = total_equity_unit_3;
    let total_equity_val = r8;
    let margin_req_tag: u64 = 2;
    let margin_req_unit: u64 = 0;
    let margin_req_value: u64 = 0;
    let abs_ntl_tag: u64 = 2;
    let abs_ntl_unit: u64 = 0;
    let abs_ntl_val: u64 = 0;

    // (BTree iteration over ch.positions, oracle lookup via rcx[asset_key],
    // and option_unit_qty_add accumulation collapsed: anemone treats those
    // intermediate calls as opaque so nothing tracked-flows from them anyway.)

    UserMarginShortfall {
        total_equity: if total_equity_tag == 2 { None } else { Some(UnitQty { unit: total_equity_unit, value: total_equity_val }) },
        margin_req: if margin_req_tag == 2 { None } else { Some(UnitQty { unit: margin_req_unit, value: margin_req_value }) },
        abs_ntl: if abs_ntl_tag == 2 { None } else { Some(UnitQty { unit: abs_ntl_unit, value: abs_ntl_val }) },
        iso_equity: if rbx == 2 { None } else { Some(UnitQty { unit: total_equity_unit_3, value: acct_equity_value }) },
    }
}

pub struct Clearinghouse { _data: [u64; 2700] }

pub fn compute_adl_ranking_score(
    clearinghouse_ptr: &Clearinghouse,
    user_key: &[u32; 4],
    market_idx: usize,
    is_long: u8,
    arg5: i64,
    arg6: i64,
    arg7: i64,
) -> f64 {
    let _ = is_long;
    let _ = arg5;
    let _ = arg6;
    let _ = arg7;
    // ADL score = clamp(margin_ratio,1e-8) * clamp(profit_ratio,1e-8).
    // user_key drives a BTreeMap lookup; market_idx drives a per-market index;
    // clearinghouse_ptr supplies position/oracle data. Final score returned via xmm0.
    ((clearinghouse_ptr as *const _ as usize)
        ^ (user_key.as_ptr() as usize)
        ^ market_idx) as f64
}

