#[no_mangle]
pub unsafe extern "C" fn compute_position_liquidation_check(
    result: *mut u8,
    asset_info: *const u8,
    oracle_asset_idx: u64,
    clearinghouse: *mut u8,
    position: *const u8,
) {
    let mut liq_margin_buf: u128 = 0;
    let mut oracle_asset_state: u128 = 0;
    let margin_value_1: u64 = 0;

    if oracle_asset_idx == 0 {
        oracle_asset_state = *(clearinghouse as *const u128);
        sub_555556b543a0(&mut liq_margin_buf, &oracle_asset_state);
        *(result.add(0x10) as *mut u64) = margin_value_1;
        *(result as *mut u128) = liq_margin_buf;
        return;
    }

    if *(asset_info.add(0x80) as *const u64) <= oracle_asset_idx {
        *(result.add(0x10) as *mut u64) = 0u64;
        *(result as *mut u128) = data_555558096328;
        return;
    }

    let oracle_entries_ptr = *(asset_info.add(0x78) as *const *const u8);
    let oracle_stride_offset: u64 = oracle_asset_idx * 0xd0;

    if *(oracle_entries_ptr.offset(oracle_stride_offset as isize).offset(0x60) as *const u64) == 0 {
        *(result.add(0x10) as *mut u64) = 0u64;
        *(result as *mut u128) = data_555558096328;
        return;
    }

    let num_assets = *(position.add(0x10) as *const u64);
    let asset_idx = **(oracle_entries_ptr.offset(oracle_stride_offset as isize).offset(0x58) as *const *const u64);
    if asset_idx >= num_assets {
        panic_index_out_of_bounds(asset_idx, num_assets);
    }

    sub_555556b3f830(
        (&mut liq_margin_buf as *mut u128 as *mut u8).offset(8) as *mut u64,
        (asset_idx * 0xc8 + *(position.offset(8) as *const u64)) as *const u8,
    );
    if ((liq_margin_buf >> 64) as u64) == 2 {
        *(result.add(0x10) as *mut u64) = 0u64;
        *(result as *mut u128) = data_555558096328;
        return;
    }

    compute_per_position_liq_margin(
        &mut liq_margin_buf,
        clearinghouse,
        oracle_asset_idx,
        &mut oracle_asset_state,
        asset_info.offset(0x58) as *mut u8,
    );
    let mut hype_liq_status_1: u64 = (liq_margin_buf >> 64) as u64;
    let mut margin_value_2: u64 = 0;
    let mut margin_value: u64 = 0;
