    if margin_value < 0x28f5c28f5c28f5c {
        margin_value_2 = margin_value;
    }

    if oracle_asset_idx != 1 {
        let asset_name_ptr = *(oracle_entries_ptr.offset(oracle_stride_offset as isize).offset(0x38) as *const *const u32);
