            let hype_liq_status: u64 = hype_liq_status_1;
            let var_40: u64 = rdx_1;
            let margin_value_3: u64 = margin_value_2;
            let hype_margin_floor: u64 = 0x2386f26fc10000;
            liq_margin_buf = 0;

            let mut min_margin_ptr: *const u64 = &hype_liq_status;
            if option_unit_qty_cmp(&hype_liq_status, &liq_margin_buf as *const u128 as *const u64) == 1 {
                min_margin_ptr = &liq_margin_buf as *const u128 as *const u64;
            }
            if min_margin_ptr == (&hype_liq_status as *const u64) {
                *(result as *mut u64) = hype_liq_status;
                *(result.offset(8) as *mut u64) = var_40;
                margin_value_2 = margin_value_3;
